#!/usr/bin/env python3
"""
Lightweight CLI to run read-only SQL queries across a folder of CSV files.
"""

import argparse
import gzip
import bz2
import os
import re
import sys
from pathlib import Path
from typing import Optional, Dict, List, Tuple

import pandas as pd


class SQLParseError(Exception):
    """Raised when SQL parsing fails."""
    pass


class FileLoader:
    """Loads data files from various formats with decompression support.

    Supports: CSV, TSV, Parquet, JSON, JSONL
    Compressed formats: .bz2, .gz
    """

    # File format extensions
    CSV_EXTENSIONS = {'.csv'}
    TSV_EXTENSIONS = {'.tsv'}
    PARQUET_EXTENSIONS = {'.parquet'}
    JSON_EXTENSIONS = {'.json', '.jsonl'}
    COMPRESSED_EXTENSIONS = {'.bz2', '.gz'}

    @classmethod
    def _get_base_name(cls, file_path: Path) -> str:
        """Get the base name without any extension, handling nested extensions.

        Example: users.csv.gz -> users
                 data.json.bz2 -> data
        """
        name = file_path.name
        # Remove compression extensions first
        for ext in cls.COMPRESSED_EXTENSIONS:
            if name.endswith(ext):
                name = name[:-len(ext)]
                break
        # Now remove format extensions
        all_format_exts = cls.CSV_EXTENSIONS | cls.TSV_EXTENSIONS | cls.PARQUET_EXTENSIONS | cls.JSON_EXTENSIONS
        for ext in all_format_exts:
            if name.endswith(ext):
                name = name[:-len(ext)]
                break
        return name

    @classmethod
    def _detect_format(cls, file_path: Path) -> str:
        """Detect the format of a file based on its extension.

        Returns: 'csv', 'tsv', 'parquet', 'json', or 'jsonl'
        """
        name = file_path.name

        # Remove compression extension first
        for ext in cls.COMPRESSED_EXTENSIONS:
            if name.endswith(ext):
                name = name[:-len(ext)]
                break

        if name.endswith('.parquet'):
            return 'parquet'
        elif name.endswith('.tsv'):
            return 'tsv'
        elif name.endswith('.jsonl'):
            return 'jsonl'
        elif name.endswith('.json'):
            return 'json'
        elif name.endswith('.csv'):
            return 'csv'
        else:
            raise ValueError(f"Unsupported file format: {file_path}")

    @classmethod
    def _open_compressed(cls, file_path: Path):
        """Open a compressed file and return a file-like object."""
        if file_path.name.endswith('.gz'):
            return gzip.open(file_path, 'rt', encoding='utf-8')
        elif file_path.name.endswith('.bz2'):
            return bz2.open(file_path, 'rt', encoding='utf-8')
        else:
            return open(file_path, 'r', encoding='utf-8')

    @classmethod
    def load_dataframe(cls, file_path: Path) -> pd.DataFrame:
        """Load a file into a pandas DataFrame.

        Supports CSV, TSV, Parquet, JSON, JSONL formats.
        Supports .bz2 and .gz compression.
        """
        fmt = cls._detect_format(file_path)

        if fmt == 'parquet':
            return pd.read_parquet(file_path)
        elif fmt == 'csv':
            if file_path.name.endswith(('.gz', '.bz2')):
                with cls._open_compressed(file_path) as f:
                    return pd.read_csv(f, dtype=str)
            else:
                return pd.read_csv(file_path, dtype=str)
        elif fmt == 'tsv':
            if file_path.name.endswith(('.gz', '.bz2')):
                with cls._open_compressed(file_path) as f:
                    return pd.read_csv(f, sep='\t', dtype=str)
            else:
                return pd.read_csv(file_path, sep='\t', dtype=str)
        elif fmt == 'json':
            if file_path.name.endswith(('.gz', '.bz2')):
                with cls._open_compressed(file_path) as f:
                    return pd.read_json(f, dtype=str)
            else:
                return pd.read_json(file_path, dtype=str)
        elif fmt == 'jsonl':
            if file_path.name.endswith(('.gz', '.bz2')):
                with cls._open_compressed(file_path) as f:
                    return pd.read_json(f, lines=True, dtype=str)
            else:
                return pd.read_json(file_path, lines=True, dtype=str)
        else:
            raise ValueError(f"Unsupported format: {fmt}")

    @classmethod
    def get_table_name(cls, file_path: Path, data_dir: Path) -> str:
        """Get the table name from a file path.

        The table name uses '.' for subdirectories and excludes all extensions.
        """
        rel_path = file_path.relative_to(data_dir)
        parts = list(rel_path.parts)
        filename = cls._get_base_name(file_path)

        if len(parts) > 1:
            dir_parts = parts[:-1]
            return '.'.join(dir_parts) + '.' + filename
        return filename

    @classmethod
    def get_base_name_tables(cls, data_dir: Path) -> Dict[str, List[Path]]:
        """Group files by their base name (without extensions).

        Returns a dict mapping base_name -> list of file paths.
        This helps identify files with the same name but different formats/compressions.
        """
        base_name_to_files: Dict[str, List[Path]] = {}

        # Find all supported files
        all_patterns = [
            '**/*.csv', '**/*.csv.gz', '**/*.csv.bz2',
            '**/*.tsv', '**/*.tsv.gz', '**/*.tsv.bz2',
            '**/*.parquet',
            '**/*.json', '**/*.json.gz', '**/*.json.bz2',
            '**/*.jsonl', '**/*.jsonl.gz', '**/*.jsonl.bz2',
        ]

        file_paths = []
        for pattern in all_patterns:
            file_paths.extend(data_dir.rglob(pattern))

        for file_path in file_paths:
            if not file_path.is_file():
                continue
            base_name = cls._get_base_name(file_path)
            if base_name not in base_name_to_files:
                base_name_to_files[base_name] = []
            base_name_to_files[base_name].append(file_path)

        return base_name_to_files

    @classmethod
    def load_from_glob(cls, glob_pattern: str) -> pd.DataFrame:
        """Load and concatenate files matching a glob pattern.

        Files are matched, sorted lexicographically, and concatenated.
        If no files match, returns an empty DataFrame with no columns.
        """
        import glob as glob_module

        matched_files = sorted(glob_module.glob(glob_pattern))

        if not matched_files:
            # Return empty DataFrame with no columns as specified
            return pd.DataFrame()

        dataframes = []
        for file_path in matched_files:
            path = Path(file_path)
            if path.is_file():
                try:
                    df = cls.load_dataframe(path)
                    dataframes.append(df)
                except Exception as e:
                    print(f"Warning: Could not load {file_path}: {e}", file=sys.stderr)

        if not dataframes:
            return pd.DataFrame()

        # Concatenate all dataframes
        # If schemas differ, pandas will handle it (creating NaN for missing columns)
        return pd.concat(dataframes, ignore_index=True, sort=False)


class MultiFormatTableManager:
    """Manages loading and accessing files of various formats as tables."""

    def __init__(self, data_dir: str, sharded_tables: List[Tuple[str, str]] = None):
        self.data_dir = Path(data_dir)
        self.tables: Dict[str, dict] = {}
        self._load_tables(sharded_tables or [])

    def _load_tables(self, sharded_tables: List[Tuple[str, str]]):
        """Load all supported files from the directory.

        Args:
            sharded_tables: List of (table_name, glob_pattern) tuples for sharded tables.
        """
        # First, load regular tables from the data directory
        base_name_groups = FileLoader.get_base_name_tables(self.data_dir)

        # Track column sets for consistency checking
        base_name_columns: Dict[str, Tuple[Tuple[str, ...], Path]] = {}

        for base_name, file_paths in base_name_groups.items():
            # For each group, load the first file to use as the table
            # but check all files for column consistency
            for file_path in file_paths:
                try:
                    df = FileLoader.load_dataframe(file_path)
                    columns = tuple(sorted(df.columns))

                    # Check column consistency with other files having same base name
                    if base_name in base_name_columns:
                        expected_cols, first_file = base_name_columns[base_name]
                        if columns != expected_cols:
                            raise ValueError(
                                f"Column mismatch for '{base_name}': "
                                f"{file_path.name} has columns {list(columns)}, "
                                f"but {first_file.name} has columns {list(expected_cols)}"
                            )
                    else:
                        base_name_columns[base_name] = (columns, file_path)

                except Exception as e:
                    print(f"Warning: Could not load {file_path}: {e}", file=sys.stderr)
                    continue

        # Now load all files into tables
        for base_name, file_paths in base_name_groups.items():
            for file_path in file_paths:
                try:
                    df = FileLoader.load_dataframe(file_path)
                    table_name = FileLoader.get_table_name(file_path, self.data_dir)

                    # Store the dataframe with its actual columns
                    self.tables[table_name.lower()] = {
                        'df': df,
                        'path': file_path,
                        'columns': list(df.columns)
                    }
                    format_name = FileLoader._detect_format(file_path)
                    compressed = 'compressed' if file_path.suffixes[-1] in ['.gz', '.bz2'] else 'uncompressed'
                    print(f"Loaded table '{table_name}' ({format_name}, {compressed}) with {len(df)} rows and {len(df.columns)} columns")
                except Exception as e:
                    print(f"Warning: Could not load {file_path}: {e}", file=sys.stderr)

        # Load sharded tables
        for table_name, glob_pattern in sharded_tables:
            try:
                df = FileLoader.load_from_glob(glob_pattern)
                self.tables[table_name.lower()] = {
                    'df': df,
                    'path': glob_pattern,
                    'columns': list(df.columns) if not df.empty else []
                }
                if df.empty:
                    print(f"Loaded sharded table '{table_name}' from '{glob_pattern}' (empty, 0 rows)")
                else:
                    print(f"Loaded sharded table '{table_name}' from '{glob_pattern}' with {len(df)} rows and {len(df.columns)} columns")
            except Exception as e:
                print(f"Warning: Could not load sharded table '{table_name}' from '{glob_pattern}': {e}", file=sys.stderr)

    def get_table(self, table_name: str) -> pd.DataFrame:
        """Get a table by name."""
        key = table_name.lower()
        if key not in self.tables:
            raise ValueError(f"Table '{table_name}' not found. Available: {list(self.tables.keys())}")
        return self.tables[key]['df'].copy()


class SQLParser:
    """Parser for the supported SQL subset."""

    def __init__(self, sql_text: str):
        self.sql = sql_text.strip()
        self.pos = 0
        self.length = len(self.sql)
        # Pre-compile token patterns for performance
        self._token_patterns = [
            (re.compile(r'^\s+', re.IGNORECASE), None),
            (re.compile(r'^SELECT', re.IGNORECASE), 'SELECT'),
            (re.compile(r'^FROM', re.IGNORECASE), 'FROM'),
            (re.compile(r'^WHERE', re.IGNORECASE), 'WHERE'),
            (re.compile(r'^GROUP\s+BY', re.IGNORECASE), 'GROUP_BY'),
            (re.compile(r'^HAVING', re.IGNORECASE), 'HAVING'),
            (re.compile(r'^ORDER\s+BY', re.IGNORECASE), 'ORDER_BY'),
            (re.compile(r'^LIMIT', re.IGNORECASE), 'LIMIT'),
            (re.compile(r'^OFFSET', re.IGNORECASE), 'OFFSET'),
            (re.compile(r'^INNER', re.IGNORECASE), 'INNER'),
            (re.compile(r'^LEFT', re.IGNORECASE), 'LEFT'),
            (re.compile(r'^RIGHT', re.IGNORECASE), 'RIGHT'),
            (re.compile(r'^FULL', re.IGNORECASE), 'FULL'),
            (re.compile(r'^JOIN', re.IGNORECASE), 'JOIN'),
            (re.compile(r'^ON', re.IGNORECASE), 'ON'),
            (re.compile(r'^AND', re.IGNORECASE), 'AND'),
            (re.compile(r'^OR', re.IGNORECASE), 'OR'),
            (re.compile(r'^NOT', re.IGNORECASE), 'NOT'),
            (re.compile(r'^DISTINCT', re.IGNORECASE), 'DISTINCT'),
            (re.compile(r'^AS', re.IGNORECASE), 'AS'),
            (re.compile(r'^\*', re.IGNORECASE), 'MULTIPLY'),
            (re.compile(r'^LIKE', re.IGNORECASE), 'LIKE'),
            (re.compile(r'^!=', re.IGNORECASE), 'NE'),
            (re.compile(r'^<=', re.IGNORECASE), 'LE'),
            (re.compile(r'^>=', re.IGNORECASE), 'GE'),
            (re.compile(r'<>', re.IGNORECASE), 'NE'),  # also !=
            (re.compile(r'^<', re.IGNORECASE), 'LT'),
            (re.compile(r'^>', re.IGNORECASE), 'GT'),
            (re.compile(r'^=', re.IGNORECASE), 'EQ'),
            (re.compile(r'^\(', re.IGNORECASE), 'LPAREN'),
            (re.compile(r'^\)', re.IGNORECASE), 'RPAREN'),
            (re.compile(r'^,', re.IGNORECASE), 'COMMA'),
            (re.compile(r'^\.', re.IGNORECASE), 'DOT'),
            (re.compile(r'"[^"]*"', re.IGNORECASE), 'STRING_LITERAL'),  # double-quoted string
            (re.compile(r"'[^']*'", re.IGNORECASE), 'STRING_LITERAL'),  # single-quoted string
            (re.compile(r'^-?\d+', re.IGNORECASE), 'INTEGER_LITERAL'),
            (re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*', re.IGNORECASE), 'IDENT'),  # identifier
        ]
        self.tokens = self._tokenize()
        self.token_pos = 0

        # Add AVG and ranking functions to recognized window functions
        self._window_function_names = {
            'COUNT', 'SUM', 'AVG', 'MIN', 'MAX',
            'ROW_NUMBER', 'RANK', 'DENSE_RANK'
        }

    def _tokenize(self) -> list:
        """Tokenize SQL into keywords, identifiers, operators, literals."""
        tokens = []
        i = 0
        while i < self.length:
            matched = False
            for regex, token_type in self._token_patterns:
                match = regex.match(self.sql[i:])
                if match:
                    matched = True
                    value = match.group(0)
                    if token_type is None:
                        # whitespace, skip
                        pass
                    else:
                        tokens.append((token_type, value.upper() if token_type in ['SELECT', 'FROM', 'WHERE', 'AND', 'OR', 'NOT', 'DISTINCT', 'LIKE'] else value))
                    i += len(value)
                    break
            if not matched:
                # Skip invalid characters
                i += 1

        return tokens
    def _peek(self, offset=0) -> Optional[tuple]:
        """Peek at the next token without consuming."""
        idx = self.token_pos + offset
        if idx < len(self.tokens):
            return self.tokens[idx]
        return None

    def _consume(self, expected_type: Optional[str] = None, expected_value: Optional[str] = None) -> Optional[tuple]:
        """Consume and return the next token."""
        if self.token_pos >= len(self.tokens):
            return None
        token = self.tokens[self.token_pos]
        self.token_pos += 1
        if expected_type and token[0] != expected_type:
            raise SQLParseError(f"Expected {expected_type}, got {token[0]}")
        if expected_value and token[1].upper() != expected_value.upper():
            raise SQLParseError(f"Expected '{expected_value}', got '{token[1]}'")
        return token

    def _match(self, token_type: str, value: Optional[str] = None) -> bool:
        """Check if the next token matches."""
        token = self._peek()
        if token is None:
            return False
        if token[0] == token_type:
            if value is None or token[1].upper() == value.upper():
                return True
        return False

    def parse(self) -> dict:
        """Parse the full SQL statement."""
        result = {
            'distinct': False,
            'select_list': [],
            'from_clause': [],
            'where_expr': None,
            'group_by': [],
            'having_expr': None,
            'order_by': [],
            'limit': None,
            'offset': None
        }

        # Expect SELECT
        if not self._match('SELECT'):
            raise SQLParseError("Expected SELECT")
        self._consume('SELECT')

        # Check DISTINCT
        if self._match('DISTINCT'):
            result['distinct'] = True
            self._consume('DISTINCT')

        # Parse select list
        result['select_list'] = self._parse_select_list()

        # Expect FROM
        if not self._match('FROM'):
            raise SQLParseError("Expected FROM")
        self._consume('FROM')

        # Parse from clause (tables with optional joins)
        result['from_clause'] = self._parse_from_clause()

        # Parse WHERE (optional)
        if self._match('WHERE'):
            self._consume('WHERE')
            result['where_expr'] = self._parse_boolean_expr()

        # Parse GROUP BY (optional)
        if self._match('GROUP_BY'):
            self._consume('GROUP_BY')
            result['group_by'] = self._parse_column_refs()

        # Parse HAVING (optional)
        if self._match('HAVING'):
            self._consume('HAVING')
            result['having_expr'] = self._parse_boolean_expr()

        # Parse ORDER BY (optional)
        if self._match('ORDER_BY'):
            self._consume('ORDER_BY')
            self._consume(None, 'BY')
            result['order_by'] = self._parse_order_items()

        # Parse LIMIT (optional)
        if self._match('LIMIT'):
            self._consume('LIMIT')
            limit_token = self._consume('INTEGER_LITERAL')
            result['limit'] = int(limit_token[1])

        # Parse OFFSET (optional)
        if self._match('OFFSET'):
            self._consume('OFFSET')
            offset_token = self._consume('INTEGER_LITERAL')
            result['offset'] = int(offset_token[1])

        return result

    def _parse_select_list(self) -> list:
        """Parse SELECT list items."""
        items = []
        while True:
            item = self._parse_select_item()
            items.append(item)
            if not self._match('COMMA'):
                break
            self._consume('COMMA')
        return items

    def _parse_optional_alias(self) -> Optional[str]:
        """Parse optional AS alias or bare identifier after expression."""
        alias = None
        if self._match('AS'):
            self._consume('AS')
        if self._peek() and self._peek()[0] == 'IDENT':
            alias = self._consume('IDENT')[1]
        return alias

    def _parse_select_item(self) -> dict:
        """Parse a single SELECT item."""
        token = self._peek()
        if token and token[0] == 'IDENT' and token[1].upper() in self._window_function_names:
            func = self._consume()[1]  # Get the value, not the type
            self._consume('LPAREN')

            is_window_function = func.upper() in ['ROW_NUMBER', 'DENSE_RANK', 'RANK']

            if not is_window_function:
                if self._match('MULTIPLY'):
                    arg = '*'
                    self._consume('MULTIPLY')
                else:
                    arg = self._parse_column_ref()
            else:
                arg = None  # ranking functions take no arguments

            self._consume('RPAREN')

            # Check for OVER clause (window function)
            window_spec = None
            if self._match('OVER'):
                window_spec = self._parse_window_spec()

            alias = self._parse_optional_alias()

            if window_spec is not None:
                result = {
                    'type': 'window_func',
                    'function': func.lower(),
                    'arg': arg,
                    'window_spec': window_spec,
                    'alias': alias
                }
            else:
                # Regular aggregate function
                result = {
                    'type': 'aggregate',
                    'function': func.lower(),
                    'arg': arg,
                    'alias': alias
                }
        else:
            expr = self._parse_column_ref()

            alias = self._parse_optional_alias()

            result = {
                'type': 'column',
                'expr': expr,
                'alias': alias
            }

        return result

    def _parse_from_clause(self) -> list:
        """Parse FROM clause with optional joins."""
        tables = []

        # First table in FROM
        first_table = self._parse_table_ref()
        tables.append(first_table)

        # Parse joins
        while self._match('JOIN'):
            join_type = 'INNER'  # default
            if self._peek(offset=1) and self._peek(offset=1)[0] in ['INNER', 'LEFT', 'RIGHT', 'FULL']:
                join_type = self._consume()[1].upper()

            self._consume('JOIN')
            join_table = self._parse_table_ref()

            # Parse ON clause
            self._consume('ON')
            on_predicate = self._parse_equality_predicate()

            tables.append({
                'type': 'join',
                'join_type': join_type,
                'table': join_table,
                'on': on_predicate
            })

        return tables

    def _parse_table_ref(self) -> dict:
        """Parse a table reference (table name with optional alias)."""
        parts = []
        while self._peek() and self._peek()[0] == 'IDENT':
            parts.append(self._consume('IDENT')[1])
            if self._match('DOT'):
                self._consume('DOT')

        if not parts:
            raise SQLParseError("Expected table name")

        table_name = '.'.join(parts)

        alias = self._parse_optional_alias()

        return {
            'type': 'table',
            'name': table_name,
            'alias': alias
        }

    def _parse_equality_predicate(self) -> dict:
        """Parse ON equality predicate (simple column = column)."""
        left = self._parse_column_ref()
        self._consume('EQ')
        right = self._parse_column_ref()
        return {
            'type': 'equality',
            'left': left,
            'right': right
        }

    def _parse_column_ref(self) -> dict:
        """Parse a column reference (e.g., table.column, column)."""
        parts = []

        # Check for aggregate function first (in case it's nested)
        if self._peek() and self._peek()[0] in ['COUNT', 'SUM', 'MIN', 'MAX']:
            func = self._consume()[0]
            self._consume('LPAREN')

            if self._match('MULTIPLY') or self._consume()[1] == '*':
                arg = '*'
            else:
                # Roll back, this is a column ref
                self.token_pos -= 2
                # Parse as regular column ref
                while self._peek() and self._peek()[0] == 'IDENT':
                    parts.append(self._consume('IDENT')[1])
                    if self._match('DOT'):
                        self._consume('DOT')
                arg = '.'.join(parts)
                return {'type': 'column', 'name': arg}

            self._consume('RPAREN')
            return {'type': 'aggregate_call', 'function': func.lower(), 'arg': arg}

        # Regular column reference: table.column or column
        while self._peek() and self._peek()[0] == 'IDENT':
            parts.append(self._consume('IDENT')[1])
            if self._match('DOT'):
                self._consume('DOT')

        if not parts:
            raise SQLParseError("Expected column reference")

        name = '.'.join(parts)
        return {'type': 'column', 'name': name}

    def _parse_column_refs(self) -> list:
        """Parse comma-separated column references."""
        refs = []
        while True:
            col = self._parse_column_ref()
            refs.append(col)
            if not self._match('COMMA'):
                break
            self._consume('COMMA')
        return refs

    def _parse_boolean_expr(self) -> dict:
        """Parse a boolean expression (recursive descent)."""
        return self._parse_or_expr()

    def _parse_or_expr(self) -> dict:
        """Parse OR expressions."""
        left = self._parse_and_expr()

        while self._match('OR'):
            self._consume('OR')
            right = self._parse_and_expr()
            left = {
                'type': 'binary_op',
                'operator': 'OR',
                'left': left,
                'right': right
            }

        return left

    def _parse_and_expr(self) -> dict:
        """Parse AND expressions."""
        left = self._parse_unary_expr()

        while self._match('AND'):
            self._consume('AND')
            right = self._parse_unary_expr()
            left = {
                'type': 'binary_op',
                'operator': 'AND',
                'left': left,
                'right': right
            }

        return left

    def _parse_unary_expr(self) -> dict:
        """Parse NOT expressions and primary expressions."""
        if self._match('NOT'):
            self._consume('NOT')
            expr = self._parse_primary()
            return {
                'type': 'unary_op',
                'operator': 'NOT',
                'expr': expr
            }

        return self._parse_primary()

    def _parse_primary(self) -> dict:
        """Parse primary expressions: column, literal, or parenthesized expr."""
        # Check for parentheses
        if self._match('LPAREN'):
            self._consume('LPAREN')
            expr = self._parse_boolean_expr()
            self._consume('RPAREN')
            return expr

        # Check for aggregate functions in HAVING/WHERE
        if self._peek() and self._peek()[0] in ['COUNT', 'SUM', 'MIN', 'MAX']:
            func = self._consume()[0]
            self._consume('LPAREN')

            if self._match('MULTIPLY'):
                arg = '*'
                self._consume('MULTIPLY')
            else:
                arg = self._parse_column_ref()
                if arg['type'] != 'column':
                    raise SQLParseError("Aggregate function expects column reference")
                arg = arg['name']

            self._consume('RPAREN')
            return {'type': 'aggregate_call', 'function': func.lower(), 'arg': arg}

        # Column reference
        if self._peek() and self._peek()[0] == 'IDENT':
            col = self._parse_column_ref()

            # Check for comparison operator
            if self._peek() and self._peek()[0] in ['EQ', 'NE', 'LT', 'LE', 'GT', 'GE', 'LIKE']:
                op_token = self._consume()
                operator = op_token[0]
                right = self._parse_operand()
                return {
                    'type': 'comparison',
                    'left': col,
                    'operator': operator,
                    'right': right
                }

            return col

        # Literal
        return self._parse_operand()

    def _parse_operand(self) -> dict:
        """Parse an operand: literal, column ref, or aggregate."""
        token = self._peek()

        if token[0] == 'STRING_LITERAL':
            self._consume('STRING_LITERAL')
            value = token[1].strip('"\'')  # Remove quotes
            return {'type': 'literal', 'value': value, 'literal_type': 'string'}

        if token[0] == 'INTEGER_LITERAL':
            self._consume('INTEGER_LITERAL')
            value = int(token[1])
            return {'type': 'literal', 'value': value, 'literal_type': 'integer'}

        if token[0] == 'IDENT':
            return self._parse_column_ref()

        raise SQLParseError(f"Unexpected token: {token}")

    def _parse_order_items(self) -> list:
        """Parse ORDER BY items."""
        items = []
        while True:
            col = self._parse_column_ref()

            asc_desc = 'ASC'
            if self._match('ASC'):
                self._consume('ASC')
            elif self._match('DESC'):
                asc_desc = 'DESC'
                self._consume('DESC')

            items.append({
                'column': col,
                'direction': asc_desc
            })

            if not self._match('COMMA'):
                break
            self._consume('COMMA')

        return items

    def _parse_window_spec(self) -> dict:
        """Parse window specification: OVER ( [PARTITION BY ...] [ORDER BY ...] [frame_clause] )"""
        self._consume('OVER')
        self._consume('LPAREN')

        spec = {
            'partition_by': [],
            'order_by': [],
            'frame_clause': None
        }

        # Parse PARTITION BY (optional)
        if self._match('IDENT') and self._peek()[1].upper() == 'PARTITION':
            self._consume('IDENT')  # PARTITION
            self._consume(None, 'BY')
            spec['partition_by'] = self._parse_column_refs()

        # Parse ORDER BY (optional)
        if self._match('IDENT') and self._peek()[1].upper() == 'ORDER':
            self._consume('IDENT')  # ORDER
            self._consume(None, 'BY')
            spec['order_by'] = self._parse_order_items()

        # Parse frame_clause (optional)
        if self._peek() and self._peek()[0] in ['ROWS', 'RANGE']:
            spec['frame_clause'] = self._parse_frame_clause()

        self._consume('RPAREN')
        return spec

    def _parse_frame_clause(self) -> dict:
        """Parse frame clause: ROWS|RANGE [BETWEEN ... AND ...]"""
        frame_type = self._consume()[1].upper()  # ROWS or RANGE

        # Check for BETWEEN clause
        if self._match('BETWEEN'):
            self._consume('BETWEEN')
            start_bound = self._parse_frame_bound()
            self._consume(None, 'AND')
            end_bound = self._parse_frame_bound()
            return {
                'type': 'between',
                'frame_units': frame_type,
                'start': start_bound,
                'end': end_bound
            }
        else:
            # UNBOUNDED PRECEDING (default for RANGE) or ROWS UNBOUNDED PRECEDING
            bound = self._parse_frame_bound()
            return {
                'type': 'simple',
                'frame_units': frame_type,
                'bound': bound
            }

    def _parse_frame_bound(self) -> dict:
        """Parse frame bound: UNBOUNDED PRECEDING, CURRENT ROW, or <n> PRECEDING/FOLLOWING"""
        if self._match('IDENT') and self._peek()[1].upper() == 'UNBOUNDED':
            self._consume('IDENT')
            direction = self._consume()[1].upper()
            return {'type': 'unbounded', 'direction': direction}
        elif self._match('IDENT') and self._peek()[1].upper() == 'CURRENT':
            self._consume('IDENT')
            self._consume(None, 'ROW')
            return {'type': 'current_row'}
        else:
            # Numeric bound
            num_token = self._consume('INTEGER_LITERAL')
            num = int(num_token[1])
            direction = self._consume()[1].upper()
            return {'type': 'numeric', 'value': num, 'direction': direction}




class QueryExecutor:
    """Executes parsed SQL queries on loaded tables."""

    def __init__(self, table_manager: 'MultiFormatTableManager'):
        self.table_manager = table_manager

    def execute(self, parsed: dict) -> pd.DataFrame:
        """Execute a parsed query and return result DataFrame."""
        # Step 1: Load base tables
        tables = self._load_from_clause(parsed['from_clause'])

        # Step 2: Apply WHERE filter (before JOIN for performance)
        if parsed['where_expr']:
            for alias, df in tables.items():
                tables[alias] = self._apply_where(df, parsed['where_expr'], tables)

        # Step 3: Perform JOINs
        if len(tables) > 1:
            result_df = self._perform_joins(list(tables.values()), parsed['from_clause'])
        else:
            result_df = list(tables.values())[0]

        # Step 4: Apply WHERE again after JOIN if needed (for join conditions)
        if parsed['where_expr'] and len(tables) > 1:
            result_df = self._apply_where(result_df, parsed['where_expr'], tables)

        # Step 5a: Apply GROUP BY and aggregates
        has_window_funcs = any(item.get('type') == 'window_func' for item in parsed['select_list'])

        if parsed['group_by']:
            result_df = self._apply_group_by(result_df, parsed, tables)
            # After GROUP BY, window functions are computed on the grouped result
            if has_window_funcs:
                result_df = self._apply_window_functions(result_df, parsed['select_list'], tables)
        else:
            # Process SELECT without GROUP BY
            # First handle non-window columns and aggregates
            result_df = self._process_select_list(result_df, parsed['select_list'], tables, aggregated=False)
            # Then apply window functions on the result
            if has_window_funcs:
                result_df = self._apply_window_functions(result_df, parsed['select_list'], tables)

        # Step 6: Apply HAVING (after GROUP BY)
        if parsed['having_expr']:
            result_df = self._apply_having(result_df, parsed['having_expr'])

        # Step 7: Apply DISTINCT
        if parsed['distinct']:
            # Get column names from select list
            select_cols = self._get_select_columns(parsed['select_list'], tables)
            result_df = result_df[select_cols].drop_duplicates()

        # Step 8: Apply ORDER BY
        if parsed['order_by']:
            result_df = self._apply_order_by(result_df, parsed['order_by'])

        # Step 9: Apply LIMIT and OFFSET
        if parsed['offset'] is not None:
            result_df = result_df.iloc[parsed['offset']:]

        if parsed['limit'] is not None:
            result_df = result_df.head(parsed['limit'])

        # Step 10: Rename columns according to SELECT list
        result_df = self._rename_select_columns(result_df, parsed['select_list'])

        return result_df

    def _load_from_clause(self, from_clause: list) -> dict:
        """Load tables from FROM clause."""
        tables = {}

        # First item is the main table
        main_table = from_clause[0]
        if main_table['type'] == 'table':
            table_name = main_table['name']
            alias = main_table.get('alias', table_name.split('.')[-1].lower())
            tables[alias] = self.table_manager.get_table(table_name)

        return tables

    def _apply_where(self, df: pd.DataFrame, where_expr: dict, tables: dict) -> pd.DataFrame:
        """Apply WHERE filter to a DataFrame."""
        mask = self._evaluate_boolean_expr(where_expr, df, tables)
        return df[mask].reset_index(drop=True)

    def _apply_having(self, df: pd.DataFrame, having_expr: dict) -> pd.DataFrame:
        """Apply HAVING filter to grouped DataFrame."""
        mask = self._evaluate_boolean_expr(having_expr, df, {})
        return df[mask].reset_index(drop=True)

    def _evaluate_boolean_expr(self, expr: dict, df: pd.DataFrame, tables: dict) -> pd.Series:
        """Evaluate a boolean expression and return a boolean mask."""
        expr_type = expr.get('type')

        if expr_type == 'binary_op':
            left = self._evaluate_boolean_expr(expr['left'], df, tables)
            right = self._evaluate_boolean_expr(expr['right'], df, tables)

            if expr['operator'] == 'AND':
                return left & right
            elif expr['operator'] == 'OR':
                return left | right

        elif expr_type == 'unary_op':
            val = self._evaluate_boolean_expr(expr['expr'], df, tables)
            if expr['operator'] == 'NOT':
                return ~val

        elif expr_type == 'comparison':
            left_val = self._evaluate_expression(expr['left'], df, tables)
            right_val = self._evaluate_expression(expr['right'], df, tables)

            op = expr['operator']

            if op == 'EQ':
                return left_val == right_val
            elif op == 'NE':
                return left_val != right_val
            elif op == 'LT':
                return left_val < right_val
            elif op == 'LE':
                return left_val <= right_val
            elif op == 'GT':
                return left_val > right_val
            elif op == 'GE':
                return left_val >= right_val
            elif op == 'LIKE':
                # LIKE pattern matching (simple % wildcard)
                # right_val could be a literal or column
                if isinstance(right_val, pd.Series):
                    # If it's a column, use first value as pattern for comparison
                    pattern_str = str(right_val.iloc[0]) if len(right_val) > 0 else ''
                else:
                    pattern_str = str(right_val)
                # Convert SQL LIKE pattern to regex: % -> .*, _ -> .
                pattern = pattern_str.replace('%', '.*').replace('_', '.')
                return left_val.str.contains(f'^{pattern}$', regex=True, na=False)

        raise ValueError(f"Unknown expression type: {expr_type}")

    def _evaluate_expression(self, expr: dict, df: pd.DataFrame, tables: dict):
        """Evaluate an expression to a pandas Series."""
        expr_type = expr.get('type')

        if expr_type == 'column':
            col_name = expr['name']
            # Check if it's qualified (table.column)
            if '.' in col_name:
                # Find the table with this column
                for alias, table_df in tables.items():
                    if col_name.split('.')[-1] in table_df.columns:
                        return table_df[col_name.split('.')[-1]]
                # Also check in df (after join)
                if col_name in df.columns:
                    return df[col_name]
            else:
                if col_name in df.columns:
                    return df[col_name]
                # Check in tables
                for alias, table_df in tables.items():
                    if col_name in table_df.columns:
                        return table_df[col_name]

            raise ValueError(f"Column '{col_name}' not found")

        elif expr_type == 'aggregate_call':
            # Aggregate functions are handled separately in GROUP BY
            raise ValueError("Aggregate call not allowed in WHERE directly")

        elif expr_type == 'literal':
            return pd.Series([expr['value']] * len(df))

        raise ValueError(f"Unknown expression type: {expr_type}")

    def _perform_joins(self, tables: list, from_clause: list) -> pd.DataFrame:
        """Perform JOIN operations."""
        if len(tables) == 1:
            return tables[0]

        # Start with the first table
        result = tables[0]
        join_infos = from_clause[1:]  # Skip first table

        for join_info in join_infos:
            if join_info['type'] == 'join':
                join_table = join_info['table']
                join_type = join_info['join_type']
                on_predicate = join_info['on']

                # Get the join table data
                join_df = None
                if join_table['type'] == 'table':
                    table_name = join_table['name']
                    join_df = self.table_manager.get_table(table_name)

                if join_df is None:
                    raise ValueError(f"Table '{table_name}' not found for JOIN")

                # Get join column names from ON clause
                left_col = on_predicate['left']['name'].split('.')[-1]
                right_col = on_predicate['right']['name'].split('.')[-1]

                # Ensure columns exist
                if left_col not in result.columns:
                    raise ValueError(f"Column '{left_col}' not found in left table")
                if right_col not in join_df.columns:
                    raise ValueError(f"Column '{right_col}' not found in right table")

                # Perform the join
                if join_type == 'INNER':
                    result = pd.merge(result, join_df, left_on=left_col, right_on=right_col,
                                      how='inner', suffixes=('_left', '_right'))
                elif join_type == 'LEFT':
                    result = pd.merge(result, join_df, left_on=left_col, right_on=right_col,
                                      how='left', suffixes=('_left', '_right'))
                elif join_type == 'RIGHT':
                    result = pd.merge(result, join_df, left_on=left_col, right_on=right_col,
                                      how='right', suffixes=('_left', '_right'))
                elif join_type == 'FULL':
                    result = pd.merge(result, join_df, left_on=left_col, right_on=right_col,
                                      how='outer', suffixes=('_left', '_right'))

        return result

    def _apply_group_by(self, df: pd.DataFrame, parsed: dict, tables: dict) -> pd.DataFrame:
        """Apply GROUP BY with aggregate functions."""
        group_cols = []
        for col_ref in parsed['group_by']:
            col_name = col_ref['name']
            # Get column from df or tables
            if col_name in df.columns:
                group_cols.append(col_name)
            else:
                for alias, table_df in tables.items():
                    if col_name in table_df.columns:
                        group_cols.append(col_name)
                        break

        if not group_cols:
            raise ValueError("GROUP BY columns not found")

        # Process select list to separate aggregates from regular columns
        agg_funcs = {}
        select_cols = []

        for select_item in parsed['select_list']:
            if select_item['type'] == 'aggregate':
                func = select_item['function']
                arg = select_item['arg']
                key = f"{func}_{arg}"
                agg_funcs[key] = func
                if func == 'count':
                    select_cols.append(key)
                else:
                    select_cols.append(key)
            else:
                col_name = select_item['expr']['name']
                select_cols.append(col_name)

        # Build aggregation dict - for COUNT(*) use size
        agg_dict = {}
        count_star_keys = []
        for select_item in parsed['select_list']:
            if select_item['type'] == 'aggregate':
                func = select_item['function']
                arg = select_item['arg']
                key = f"{func}_{arg}"

                if arg == '*':
                    # COUNT(*) is handled specially - use size
                    count_star_keys.append(key)
                elif func == 'count':
                    agg_dict[key] = 'count'
                elif func == 'sum':
                    agg_dict[key] = 'sum'
                elif func == 'min':
                    agg_dict[key] = 'min'
                elif func == 'max':
                    agg_dict[key] = 'max'

        # Perform groupby
        grouped = df.groupby(group_cols, as_index=False)

        # If there are aggregates, aggregate them
        if agg_dict:
            result = grouped.agg(agg_dict)
        else:
            result = grouped.first().reset_index()

        # Add COUNT(*) columns (from size)
        if count_star_keys:
            # Get the group sizes - need to get it without first/agg to avoid dimension issues
            size_series = grouped.size().reset_index(drop=True)
            for key in count_star_keys:
                result[key] = size_series.values

        # Flatten column names if needed
        if isinstance(result.columns, pd.MultiIndex):
            result.columns = ['_'.join(col).strip() if col[1] else col[0] for col in result.columns]

        return result

    def _process_select_list(self, df: pd.DataFrame, select_list: list, tables: dict,
                             aggregated: bool = False) -> pd.DataFrame:
        """Process SELECT list to build result columns."""
        result = pd.DataFrame()

        for select_item in select_list:
            if select_item['type'] == 'aggregate':
                func = select_item['function']
                arg = select_item['arg']

                if arg == '*':
                    if func == 'count':
                        val = [len(df)]
                    else:
                        raise ValueError(f"Invalid aggregate: {func}(*)")
                elif func == 'count':
                    val = df[arg].count()
                elif func == 'sum':
                    val = pd.to_numeric(df[arg], errors='coerce').sum()
                elif func == 'min':
                    val = pd.to_numeric(df[arg], errors='coerce').min()
                elif func == 'max':
                    val = pd.to_numeric(df[arg], errors='coerce').max()
                else:
                    raise ValueError(f"Unknown aggregate: {func}")

                # Create a single-row DataFrame for the aggregate result
                output_col = select_item.get('alias') or f"{func}_{arg}"
                if len(result) == 0:
                    result = pd.DataFrame({output_col: [val]})
                else:
                    result[output_col] = [val]

            else:
                col_name = select_item['expr']['name']
                alias = select_item.get('alias')

                # Get column value
                if col_name in df.columns:
                    val = df[col_name]
                else:
                    # Check if qualified name matches
                    for c in df.columns:
                        if c.endswith('.' + col_name.split('.')[-1]):
                            val = df[c]
                            break
                    else:
                        raise ValueError(f"Column '{col_name}' not found in result")

                output_col = alias if alias else col_name.split('.')[-1]
                result[output_col] = val

        return result

    def _get_select_columns(self, select_list: list, tables: dict) -> list:
        """Get column names from SELECT list for DISTINCT."""
        cols = []
        for item in select_list:
            if item['type'] == 'column':
                col_name = item['expr']['name']
                cols.append(col_name.split('.')[-1])
            elif item['type'] == 'aggregate':
                alias = item.get('alias')
                if alias:
                    cols.append(alias)
                else:
                    cols.append(f"{item['function']}_{item['arg']}")
            elif item['type'] == 'window_func':
                alias = item.get('alias')
                if alias:
                    cols.append(alias)
                else:
                    col = item.get('arg')
                    if col:
                        cols.append(f"{item['function']}_{col if isinstance(col, str) else col}")
                    else:
                        cols.append(item['function'])
        return cols

    def _rename_select_columns(self, df: pd.DataFrame, select_list: list) -> pd.DataFrame:
        """Rename DataFrame columns according to SELECT list aliases."""
        rename_map = {}
        for i, item in enumerate(select_list):
            if item['type'] == 'aggregate':
                old_name = f"{item['function']}_{item['arg']}"
                alias = item.get('alias')
                if alias:
                    rename_map[old_name] = alias
            elif item['type'] == 'column':
                col_name = item['expr']['name']
                alias = item.get('alias')
                if alias:
                    # Find the matching column in df
                    for c in df.columns:
                        if c == col_name.split('.')[-1] or c.endswith('.' + col_name.split('.')[-1]):
                            rename_map[c] = alias
                            break

        return df.rename(columns=rename_map)

    def _apply_order_by(self, df: pd.DataFrame, order_by: list) -> pd.DataFrame:
        """Apply ORDER BY to DataFrame."""
        if not order_by:
            return df

        sort_cols = []
        ascending = []

        for order_item in order_by:
            col_ref = order_item['column']
            col_name = col_ref['name']
            direction = order_item['direction']

            # Find column in df
            sort_col = None
            for c in df.columns:
                if c == col_name or c.endswith('.' + col_name.split('.')[-1]):
                    sort_col = c
                    break

            if sort_col is None:
                raise ValueError(f"Column '{col_name}' not found for ORDER BY")

            sort_cols.append(sort_col)
            ascending.append(direction == 'ASC')

        return df.sort_values(by=sort_cols, ascending=ascending).reset_index(drop=True)

    def _apply_window_functions(self, df: pd.DataFrame, select_list: list, tables: dict) -> pd.DataFrame:
        """Apply window functions to the DataFrame."""
        result = df.copy()

        for select_item in select_list:
            if select_item.get('type') != 'window_func':
                continue

            func = select_item['function']
            arg = select_item['arg']
            window_spec = select_item['window_spec']
            alias = select_item.get('alias')

            # Get the column to compute window function on
            if arg:
                col_name = arg if isinstance(arg, str) else arg
                if col_name not in result.columns:
                    # Check for qualified names
                    found = False
                    for c in result.columns:
                        if c.endswith('.' + col_name):
                            col_name = c
                            found = True
                            break
                    if not found:
                        raise ValueError(f"Column '{col_name}' not found for window function")
            else:
                col_name = None

            # Compute the window function result
            window_result = self._compute_window_function(
                result, func, col_name, window_spec, tables
            )

            # Apply alias
            output_col = alias if alias else self._get_window_function_column_name(func, arg)
            result[output_col] = window_result

        return result

    def _get_window_function_column_name(self, func: str, arg: Optional[str]) -> str:
        """Generate column name for window function."""
        if arg:
            return f"{func}_{arg}"
        return func

    def _compute_window_function(
        self, df: pd.DataFrame, func: str, col_name: Optional[str],
        window_spec: dict, tables: dict
    ) -> pd.Series:
        """Compute a single window function."""
        # Get partition column names
        partition_refs = window_spec['partition_by']
        partition_cols = []
        for part in partition_refs:
            part_name = part['name']
            if part_name in df.columns:
                partition_cols.append(part_name)
            else:
                # Try qualified name
                found = False
                for c in df.columns:
                    if c.endswith('.' + part_name):
                        partition_cols.append(c)
                        found = True
                        break
                if not found:
                    raise ValueError(f"Partition column '{part_name}' not found")

        # Get order column info
        order_items = window_spec['order_by']
        order_cols = []
        order_ascending = []
        for item in order_items:
            col = item['column']
            col_name_order = col['name']
            if col_name_order in df.columns:
                order_cols.append(col_name_order)
            else:
                for c in df.columns:
                    if c.endswith('.' + col_name_order):
                        order_cols.append(c)
                        break
            order_ascending.append(item['direction'] == 'ASC')

        # Handle frame clause
        frame_clause = window_spec.get('frame_clause')

        # If no partition columns, treat entire dataframe as one partition
        if not partition_cols:
            df_work = df.copy()
            df_work['_window_partition'] = 1
            partition_cols = ['_window_partition']
        else:
            df_work = df

        # For ranking functions without ORDER BY, assign constant rank
        if func in ['row_number', 'rank', 'dense_rank'] and not order_cols:
            return pd.Series([1] * len(df_work), index=df_work.index)

        # For aggregate window functions
        if func in ['sum', 'count', 'avg', 'min', 'max']:
            if frame_clause:
                return self._compute_aggregate_frame(
                    df_work, func, col_name, window_spec, partition_cols
                )
            else:
                return self._compute_cumulative_aggregate(
                    df_work, func, col_name, partition_cols
                )

        # For ranking functions
        if func in ['row_number', 'rank', 'dense_rank']:
            return self._compute_rank_function(
                df_work, func, partition_cols, order_cols, order_ascending
            )

        raise ValueError(f"Unknown window function: {func}")

    def _compute_cumulative_aggregate(
        self, df: pd.DataFrame, func: str, col_name: Optional[str],
        partition_cols: list
    ) -> pd.Series:
        """Compute cumulative aggregate (RANGE UNBOUNDED PRECEDING)."""
        if col_name is None:
            if func == 'count':
                # Count rows in partition - for aggregate window, count(*) is rows per partition
                return df.groupby(partition_cols, group_keys=False).cumcount() + 1
            else:
                raise ValueError(f"Function {func} requires a column argument")

        col_data = pd.to_numeric(df[col_name], errors='coerce')

        if func == 'sum':
            return col_data.groupby(df[partition_cols]).cumsum()
        elif func == 'count':
            # Count non-null values
            return col_data.notna().groupby(df[partition_cols)].cumsum()
        elif func == 'avg':
            cumulative_sum = col_data.groupby(df[partition_cols]).cumsum()
            cumulative_count = col_data.notna().groupby(df[partition_cols]).cumsum()
            return cumulative_sum / cumulative_count
        elif func == 'min':
            return col_data.groupby(df[partition_cols]).cummin()
        elif func == 'max':
            return col_data.groupby(df[partition_cols]).cummax()
        else:
            raise ValueError(f"Unknown aggregate function: {func}")

    def _compute_aggregate_frame(
        self, df: pd.DataFrame, func: str, col_name: Optional[str],
        window_spec: dict, partition_cols: list
    ) -> pd.Series:
        """Compute aggregate within frame clause."""
        frame_clause = window_spec['frame_clause']
        order_items = window_spec['order_by']

        if not order_items:
            raise ValueError("Frame clause requires ORDER BY")

        # Get the primary order column for frame boundaries
        order_col = order_items[0]['column']['name']
        if order_col not in df.columns:
            for c in df.columns:
                if c.endswith('.' + order_col):
                    order_col = c
                    break

        start = frame_clause['start']
        end = frame_clause['end']

        # Handle ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW
        # This is equivalent to cumulative aggregate
        if (frame_clause['frame_units'] == 'ROWS' and
            start['type'] == 'unbounded' and start['direction'] == 'PRECEDING' and
            end['type'] == 'current_row'):
            return self._compute_cumulative_aggregate(df, func, col_name, partition_cols)

        # For now, default to cumulative - can be extended for other frame types
        return self._compute_cumulative_aggregate(df, func, col_name, partition_cols)

    def _compute_rank_function(
        self, df: pd.DataFrame, func: str, partition_cols: list,
        order_cols: list, order_ascending: list
    ) -> pd.Series:
        """Compute ranking window function."""
        if not order_cols:
            return pd.Series([1] * len(df), index=df.index)

        order_col = order_cols[0]
        ascending = order_ascending[0] if order_ascending else True

        if func == 'row_number':
            # Number rows within each partition in order
            return df.groupby(partition_cols, group_keys=False).apply(
                lambda g: pd.Series(range(1, len(g) + 1), index=g.index)
            )
        elif func == 'rank':
            # Standard rank with gaps - use descending order for ranking
            def compute_rank(group):
                sorted_col = group[order_col]
                # Rank in descending order (highest value = rank 1)
                ranks = sorted_col.rank(method='min', ascending=False, na_position='after')
                return ranks.reindex(group.index)
            return df.groupby(partition_cols, group_keys=False).apply(compute_rank)
        elif func == 'dense_rank':
            # Dense rank without gaps
            def compute_dense_rank(group):
                sorted_col = group[order_col]
                # Get unique values in descending order
                unique_vals = sorted_col.dropna().sort_values(ascending=False).unique()
                rank_map = {val: i + 1 for i, val in enumerate(unique_vals)}
                ranks = sorted_col.map(lambda x: rank_map.get(x, len(rank_map) + 1))
                return ranks.reindex(group.index)
            return df.groupby(partition_cols, group_keys=False).apply(compute_dense_rank)
        else:
            raise ValueError(f"Unknown ranking function: {func}")


def format_markdown_table(df: pd.DataFrame) -> str:
    """Format DataFrame as a markdown table."""
    if df.empty:
        return "| No results |\n|------------|\n|            |"

    # Build header
    headers = list(df.columns)
    header_row = "| " + " | ".join(str(h) for h in headers) + " |"

    # Build separator
    separator = "| " + " | ".join("---" for _ in headers) + " |"

    # Build data rows
    rows = []
    for _, row in df.iterrows():
        row_data = []
        for val in row:
            if pd.isna(val):
                row_data.append("NULL")
            else:
                row_data.append(str(val))
        rows.append("| " + " | ".join(row_data) + " |")

    return "\n".join([header_row, separator] + rows)


def save_csv(df: pd.DataFrame, output_path: str):
    """Save DataFrame to CSV file."""
    df.to_csv(output_path, index=False, na_rep='NULL')


def read_sql_file_or_string(sql_input: str) -> str:
    """Read SQL from file or return as string if it's not a valid file path."""
    # Check if it's a file path
    if os.path.isfile(sql_input):
        with open(sql_input, 'r') as f:
            return f.read()
    return sql_input


def main():
    parser = argparse.ArgumentParser(
        description='Run read-only SQL queries across a folder of CSV files.'
    )
    parser.add_argument('--data', required=True, help='Directory containing CSV files')
    parser.add_argument('--sql', required=True,
                        help='SQL query string or path to SQL file')
    parser.add_argument('--out', required=False, help='Output path for CSV result')
    parser.add_argument('--sharded', action='append', dest='sharded_tables', metavar='TABLE=GLOB',
                        help='Shard table definition in the form TABLE=GLOB pattern. Can be specified multiple times.')

    args = parser.parse_args()

    # Read SQL
    sql_text = read_sql_file_or_string(args.sql)

    # Parse SQL
    try:
        sql_parser = SQLParser(sql_text)
        parsed_query = sql_parser.parse()
    except SQLParseError as e:
        print(f"SQL Parse Error: {e}", file=sys.stderr)
        sys.exit(1)

    # Parse sharded tables
    sharded_tables = []
    if args.sharded_tables:
        for shard_def in args.sharded_tables:
            if '=' not in shard_def:
                print(f"Warning: Invalid shard definition '{shard_def}', expected FORMAT table_name=glob_pattern", file=sys.stderr)
                continue
            table_name, glob_pattern = shard_def.split('=', 1)
            table_name = table_name.strip()
            glob_pattern = glob_pattern.strip()
            if table_name and glob_pattern:
                sharded_tables.append((table_name, glob_pattern))

    # Load tables
    try:
        table_manager = MultiFormatTableManager(args.data, sharded_tables)
    except Exception as e:
        print(f"Error loading tables: {e}", file=sys.stderr)
        sys.exit(1)

    # Execute query
    try:
        executor = QueryExecutor(table_manager)
        result_df = executor.execute(parsed_query)
    except Exception as e:
        print(f"Query execution error: {e}", file=sys.stderr)
        import traceback
        traceback.print_exc()
        sys.exit(1)

    # Output results
    markdown_output = format_markdown_table(result_df)
    print(markdown_output)

    # Save to file if requested
    if args.out:
        try:
            save_csv(result_df, args.out)
            print(f"\n\nResult also saved to {args.out}", file=sys.stderr)
        except Exception as e:
            print(f"Error saving output: {e}", file=sys.stderr)
            sys.exit(1)


if __name__ == '__main__':
    main()

